use core::fmt;

pub struct LedDriver {
    pins: [bool; 8],
}

impl LedDriver {
    pub fn new() -> Self {
        LedDriver { pins: [false; 8] }
    }

    pub fn set_pins(&mut self, pins: &[bool]) {
        for (i, &p) in pins.iter().enumerate() {
            self.pins[i] = p;
        }
    }

    pub fn get_pins(&self) -> &[bool] {
        &self.pins
    }
}

fn main() {}
